INSERT INTO competencias (grado, area, texto_completo, indicadores) VALUES
('Primero Básico', 'Matemática', '1. Identifica elementos comunes en patrones algebraicos y geométricos.', ARRAY['1.1 Representa información cuantitativa generalizada a partir de variables.', '1.2 Reconoce figuras, relaciones, propiedades y medidas en diseños propuestos.', '1.3 Calcula áreas y perímetros de polígonos regulares.']),
('Primero Básico', 'Matemática', '2. Utiliza gráficas y símbolos en la representación de información y solución de problemas.', ARRAY['2.1 Construye proposiciones compuestas usando conectivos lógicos.', '2.2 Representa de forma simbólica y gráfica las relaciones entre variables.', '2.3 Distingue entre relaciones y funciones.', '2.4 Aplica ecuaciones de primer grado en la resolución de problemas.']),
('Primero Básico', 'Matemática', '3. Calcula operaciones combinadas de los diferentes conjuntos numéricos (naturales, enteros y racionales) con algoritmos escritos, mentales, exactos y aproximados.', ARRAY['3.1 Opera dentro de los conjuntos numéricos naturales y enteros, mediante procedimientos correspondientes.', '3.2 Identifica la representación y ubicación del conjunto de los racionales al realizar operaciones jerarquizadas y estimaciones.', '3.3 Aplica razones y proporciones al resolver problemas.']),
('Primero Básico', 'Matemática', '4. Interpreta información estadística representada en tablas, esquemas y gráficos.', ARRAY['4.1 Aplica procedimientos estadísticos y medidas de tendencia central para datos no agrupados.', '4.2 Tabula datos sin agrupar para representarlos y determinar su frecuencia.', '4.3 Grafica polígonos de frecuencias e histogramas que representan los datos.']),
('Primero Básico', 'Matemática', '5. Establece estrategias variadas al resolver problemas que surgen del contexto para matematizarlos.', ARRAY['5.1 Relaciona los sistemas de medidas para calcular sus equivalencias.', '5.2 Reconoce la función del universo, tiempo y espacio con enfoque cultural.', '5.3 Identifica patrones y características del sistema vigesimal.']);
